from collections import Counter
from typing import List


def merge_interv(interv: List[List]):
    ctr = Counter()
    for st,en in interv:
        ctr[st] += 1
        ctr[en] -= 1

    sm = 0
    start = None
    ans = []
    for k in sorted(ctr.keys()):
        if ctr[k] == 0:
            continue

        if start is None:
            start = k
        else:
            ans.append(f'[{start},{k}] -> {sm}')
            start = k
        sm += ctr[k]
    return '\n'.join(ans)


if __name__ == '__main__':
    print(merge_interv([[0,1], [1,3], [2,4], [3,5]]))
