import re

def skip_char(s, col, regex):
    if not s:
        return col
    j = col
    while j < len(s) and re.match(regex, s[j]):
        j += 1
    return j


def _parse(s: str, col):
    j = skip_char(s, 0, r'\s')
    if not s[j:]:
        return

    if s[j:j+3] == 'add' or s[j:j+3] == 'sub':
        j = skip_char(s, j + 3, r'\s')
        if s[j] != '(':
            raise ValueError(f'No braces starting at col {col+j}')
        j += _parse(s[j+1:],col+j+1)
        j = skip_char(s, j, r'\s')
        if j >= len(s) or (j<len(s) and s[j] != ','):
            raise ValueError(f'Missing 1 , at col {col+j}')
        j += _parse(s[j+1:], col + j + 1)
    elif s[j].isdigit():
        j = skip_char(s, j, r'\d')
        j = skip_char(s, j, r'\s')

        if j >= len(s) or s[j] == "," or s[j] == ")":
            return j+1
        else:
            raise ValueError(f'Inval char at col {col + j}')
    else:
        raise ValueError(f'Bad op at col {col+j}')

    j = skip_char(s, j, r'\s')
    if j >= len(s) or s[j] != ")":
        raise ValueError(f'Missing ) at col {col + j}')
    return j+2

def parseStr(s: str):
    try:
        ret = _parse(s,0)
        if ret < len(s):
            raise ValueError(f"Extra chars at col {ret}")
        print("Parsed successfully.")
    except ValueError as ve:
        print(ve)


if __name__ == '__main__':
    parseStr("add(sub(3,4), 1) ")
    parseStr(" sub(add(238943, 2343), add(1, sub(323, 43))) ")

    parseStr(" sub(add(238943a, 2343), add(1, sub(323, 43))) ")  # Inval char at col 15
    parseStr(" sub(add(238943, 2343, sub(1,2)), add(1, sub(323, 43)))) ")  # Missing ) at col 21
    parseStr(" sub(add(238943, 2343), add(1, sub(323, 43)))) ")  # Extra chars at col 46
    parseStr("foo(1, 2)")  # Bad op at col 0
    parseStr("add(a, 3)")  # Bad op at col 4
