  public static void main(String[] args) {
    Uber uber = new Uber();
    System.out.println(uber.evaluateExpr("add(1,3)"));
    System.out.println(uber.evaluateExpr("sub(1,3)"));
    System.out.println(uber.evaluateExpr("add(add(3,4), add(1,3))"));
    System.out.println(uber.evaluateExpr("add(add(add(3,4 ), 4), add( 1,3 ))"));

  }

  private int evaluateExpr(String input) {
    input = input.trim();

    if (input.length() == 0) {
      return 0;
    }
    if (isNumber(input.trim())) {
      return Integer.valueOf(input);
    }

    int openIndex = input.indexOf("(");
    int closeIndex = input.lastIndexOf(")");
    String oper = input.substring(0, openIndex);//add sub

    String subInp = input.substring(openIndex + 1, closeIndex);
    int count = 0;
    int ind = 0;
    int commaInd = -1; //add( 2)
    // subInp "123, add(1,1)"
    while (ind < subInp.length()) {
      char ch = subInp.charAt(ind);
      if (ch == '(') {
        count++;
      } else if (ch == ')') { //) or 2
        count--;
      }
      if (count == 0 && ch == ',') {
        commaInd = ind;
        break;
      }
      ind++;
    }
    String input1 = subInp.substring(0, commaInd);
    String input2 = subInp.substring(commaInd + 1);
    //2, exp - >
    if (oper.equals("add")) {
      return evaluateExpr(input1) + evaluateExpr(input2);
    } else if(oper.equals("sub")) {
      return evaluateExpr(input1) - evaluateExpr(input2);
    } else {
      return 0;
    }

  }

  private boolean isNumber(String val) {
    int i=0;
    for(i= 0; i<val.length(); i++) {
      if(!Character.isDigit(val.charAt(i))) {
        return false;
      }
    }
    return true;
  }
